mapper.select:
SELECT m.mode_id, m.mode_name, m.mode_type, m.category_id, m.mode_color, m.mode_icon, m.description, m.enabled, COALESCE(h.usage_count, 0) as usage_count, COALESCE(r.robot_count, 0) as robot_count, m.order_num, m.del_flag, m.tenant_id, m.create_by, m.create_time, m.update_by, m.update_time FROM sys_mode m LEFT JOIN ( SELECT mode_id, COUNT(*) as usage_count FROM sys_mode_history WHERE mode_id IS NOT NULL
AND tenant_id = #{tenantId}
GROUP BY mode_id ) h ON m.mode_id = h.mode_id LEFT JOIN ( SELECT current_mode as mode_id, COUNT(DISTINCT robot_id) as robot_count FROM sys_robot_ext WHERE current_mode IS NOT NULL AND del_flag = '0'
AND tenant_id = #{tenantId}
GROUP BY current_mode ) r ON m.mode_id = r.mode_id
AND m.mode_name like concat('%', #{modeName}, '%')
AND m.mode_type = #{modeType}
AND m.category_id = #{categoryId}
AND m.enabled = #{enabled}
AND m.tenant_id = #{tenantId}
AND m.del_flag = '0'
order by m.order_num

mapper.update:
update sys_mode
mode_name = #{modeName}, mode_type = #{modeType}, category_id = #{categoryId}, mode_color = #{modeColor}, mode_icon = #{modeIcon}, description = #{description}, enabled = #{enabled}, order_num = #{orderNum}, update_by = #{updateBy}, update_time = sysdate()
where mode_id = #{modeId}

UPDATE sys_mode m
SET m.robot_count = (
SELECT COUNT(DISTINCT e.robot_id)
FROM sys_robot_ext e
WHERE e.current_mode = m.mode_id
AND e.del_flag = '0'

    AND e.tenant_id = #{tenantId}

)
WHERE m.del_flag = '0'

    AND m.tenant_id = #{tenantId}

UPDATE sys_mode m
SET m.usage_count = (
SELECT COUNT(*)
FROM sys_mode_history h
WHERE h.mode_id = m.mode_id

    AND h.tenant_id = #{tenantId}

)
WHERE m.del_flag = '0'

    AND m.tenant_id = #{tenantId}
